package ssg
package js
package compress

import CompressTestHelper.{ AllOff, assertCompresses }

final class CompressNumbersSuite extends munit.FunSuite {

  override val munitTimeout = scala.concurrent.duration.Duration(120, "s")

  // =========================================================================
  // comparisons
  // =========================================================================
  test("comparisons") {
    assertCompresses(
      input = """console.log(
            ~x === 42,
            x % n === 42
        )""".stripMargin.trim,
      expected = """console.log(
            ~x === 42,
            x % n === 42
        )""".stripMargin.trim,
      options = AllOff.copy(
        comparisons = true
      )
    )
  }

  // =========================================================================
  // evaluate_1
  // =========================================================================
  test("evaluate_1".fail) {
    assertCompresses(
      input = """console.log(
            x + 1 + 2,
            x * 1 * 2,
            +x + 1 + 2,
            1 + x + 2 + 3,
            1 | x | 2 | 3,
            1 + x-- + 2 + 3,
            1 + (x*y + 2) + 3,
            1 + (2 + x + 3),
            1 + (2 + ~x + 3),
            -y + (2 + ~x + 3),
            1 & (2 & x & 3),
            1 + (2 + (x |= 0) + 3)
        )""".stripMargin.trim,
      expected = """console.log(
            x + 1 + 2,
            x * 1 * 2,
            +x + 1 + 2,
            1 + x + 2 + 3,
            3 | x,
            1 + x-- + 2 + 3,
            x*y + 2 + 1 + 3,
            1 + (2 + x + 3),
            2 + ~x + 3 + 1,
            -y + (2 + ~x + 3),
            0 & x,
            2 + (x |= 0) + 3 + 1
        )""".stripMargin.trim,
      options = AllOff.copy(
        evaluate = true,
        unsafeMath = false
      )
    )
  }

  // =========================================================================
  // evaluate_2
  // =========================================================================
  test("evaluate_2".fail) {
    assertCompresses(
      input = """console.log(
            x + 1 + 2,
            x * 1 * 2,
            +x + 1 + 2,
            1 + x + 2 + 3,
            1 | x | 2 | 3,
            1 + x-- + 2 + 3,
            1 + (x*y + 2) + 3,
            1 + (2 + x + 3),
            1 & (2 & x & 3),
            1 + (2 + (x |= 0) + 3)
        )""".stripMargin.trim,
      expected = """console.log(
            x + 1 + 2,
            2 * x,
            3 + +x,
            1 + x + 2 + 3,
            3 | x,
            6 + x--,
            6 + x*y,
            1 + (2 + x + 3),
            0 & x,
            6 + (x |= 0)
        )""".stripMargin.trim,
      options = AllOff.copy(
        evaluate = true,
        unsafeMath = true
      )
    )
  }

  // =========================================================================
  // evaluate_3
  // =========================================================================
  test("evaluate_3".fail) {
    assertCompresses(
      input = "console.log(1 + Number(x) + 2)",
      expected = "console.log(3 + +x)",
      options = AllOff.copy(
        evaluate = true,
        unsafe = true,
        unsafeMath = true
      )
    )
  }

  // =========================================================================
  // evaluate_4
  // =========================================================================
  test("evaluate_4".fail) {
    assertCompresses(
      input = """console.log(
            1+ +a,
            +a+1,
            1+-a,
            -a+1,
            +a+ +b,
            +a+-b,
            -a+ +b,
            -a+-b
        )""".stripMargin.trim,
      expected = """console.log(
            +a+1,
            +a+1,
            1-a,
            1-a,
            +a+ +b,
            +a-b,
            -a+ +b,
            -a-b
        )""".stripMargin.trim,
      options = AllOff.copy(
        evaluate = true
      )
    )
  }

  // =========================================================================
  // issue_1710
  // =========================================================================
  test("issue_1710") {
    assertCompresses(
      input = """var x = {};
        console.log((x += 1) + -x);
        console.log((x = x + 1) + -x)""".stripMargin.trim,
      expected = """var x = {};
        console.log((x += 1) + -x);
        console.log((x += 1) + -x)""".stripMargin.trim,
      options = AllOff.copy(
        evaluate = true
      )
    )
  }

  // =========================================================================
  // unary_binary_parenthesis
  // =========================================================================
  test("unary_binary_parenthesis") {
    assertCompresses(
      input = """var v = [ 0, 1, NaN, Infinity, null, undefined, true, false, "", "foo", /foo/ ];
        v.forEach(function(x) {
            v.forEach(function(y) {
                console.log(
                    +(x*y),
                    +(x/y),
                    +(x%y),
                    -(x*y),
                    -(x/y),
                    -(x%y)
                );
            });
        })""".stripMargin.trim,
      expected = """var v = [ 0, 1, NaN, 1/0, null, void 0, true, false, "", "foo", /foo/ ];
        v.forEach(function(x) {
            v.forEach(function(y) {
                console.log(
                    +x*y,
                    +x/y,
                    +x%y,
                    -x*y,
                    -x/y,
                    -x%y
                );
            });
        })""".stripMargin.trim,
      options = AllOff
    )
  }

  // =========================================================================
  // compress_numbers
  // =========================================================================
  test("compress_numbers".fail) {
    assertCompresses(
      input = """const exp = 1000;
        const Exp = 1000000000000;
        const negativeExp = 0.00000001;
        const huge = 1000000000001;
        const big = 100000000001;
        const fractional = 100.2300200""".stripMargin.trim,
      expected = """const exp = 1e3;
        const Exp = 1e12;
        const negativeExp = 1e-8;
        const huge = 0xe8d4a51001;
        const big = 100000000001;
        const fractional = 100.23002""".stripMargin.trim,
      options = AllOff
    )
  }

  // =========================================================================
  // no_number_function_transform_without_unsafe_math
  // =========================================================================
  test("no_number_function_transform_without_unsafe_math") {
    assertCompresses(
      input = "Number(1234)",
      expected = "Number(1234)",
      options = AllOff.copy(
        unsafe = true
      )
    )
  }

  // =========================================================================
  // number_function_transform_with_unsafe_math
  // =========================================================================
  test("number_function_transform_with_unsafe_math") {
    assertCompresses(
      input = "Number(1234)",
      expected = "+1234",
      options = AllOff.copy(
        unsafe = true,
        unsafeMath = true
      )
    )
  }

  // =========================================================================
  // large_numbers_converted_to_infinity
  // =========================================================================
  test("large_numbers_converted_to_infinity") {
    assertCompresses(
      input = "console.log(Infinity),console.log(1e500),console.log(-1e500)",
      expected = "console.log(1/0),console.log(1/0),console.log(-1/0)",
      options = AllOff
    )
  }

}
